import{_ as s,o as e,c as n,ag as i}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"exe.dev","description":"원격 액세스를 위해 exe.dev (VM + HTTPS 프록시)에서 OpenClaw Gateway 실행","frontmatter":{"title":"exe.dev","description":"원격 액세스를 위해 exe.dev (VM + HTTPS 프록시)에서 OpenClaw Gateway 실행"},"headers":[],"relativePath":"install/exe-dev.md","filePath":"install/exe-dev.md","lastUpdated":null}'),t={name:"install/exe-dev.md"};function l(p,a,o,h,d,r){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="exe-dev" tabindex="-1">exe.dev <a class="header-anchor" href="#exe-dev" aria-label="Permalink to &quot;exe.dev&quot;">​</a></h1><p>목표: exe.dev VM에서 실행되고 <code>https://&lt;vm-name&gt;.exe.xyz</code>를 통해 노트북에서 도달할 수 있는 OpenClaw Gateway</p><p>이 페이지는 exe.dev의 기본 <strong>exeuntu</strong> 이미지를 가정합니다. 다른 배포판을 선택한 경우 패키지를 적절히 매핑하십시오.</p><h2 id="초보자-빠른-경로" tabindex="-1">초보자 빠른 경로 <a class="header-anchor" href="#초보자-빠른-경로" aria-label="Permalink to &quot;초보자 빠른 경로&quot;">​</a></h2><ol><li><a href="https://exe.new/openclaw" target="_blank" rel="noreferrer">https://exe.new/openclaw</a></li><li>필요에 따라 인증 키/토큰 입력</li><li>VM 옆의 &quot;Agent&quot;를 클릭하고 Shelley의 프로비저닝 완료를 기다립니다</li><li><code>https://&lt;vm-name&gt;.exe.xyz/</code>를 열고 구성된 공유 시크릿으로 인증합니다(이 가이드는 기본적으로 토큰 인증을 사용하지만 <code>gateway.auth.mode</code>를 전환하면 비밀번호 인증도 작동합니다)</li><li><code>openclaw devices approve &lt;requestId&gt;</code>로 보류 중인 장치 페어링 요청을 승인합니다</li></ol><h2 id="필요-사항" tabindex="-1">필요 사항 <a class="header-anchor" href="#필요-사항" aria-label="Permalink to &quot;필요 사항&quot;">​</a></h2><ul><li>exe.dev 계정</li><li><a href="https://exe.dev" target="_blank" rel="noreferrer">exe.dev</a> 가상 머신에 대한 <code>ssh exe.dev</code> 액세스 (선택적)</li></ul><h2 id="shelley를-사용한-자동-설치" tabindex="-1">Shelley를 사용한 자동 설치 <a class="header-anchor" href="#shelley를-사용한-자동-설치" aria-label="Permalink to &quot;Shelley를 사용한 자동 설치&quot;">​</a></h2><p><a href="https://exe.dev" target="_blank" rel="noreferrer">exe.dev</a>의 에이전트인 Shelley는 프롬프트를 통해 OpenClaw를 즉시 설치할 수 있습니다. 사용되는 프롬프트는 다음과 같습니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Set up OpenClaw (https://docs.openclaw.ai/install) on this VM. Use the non-interactive and accept-risk flags for openclaw onboarding. Add the supplied auth or token as needed. Configure nginx to forward from the default port 18789 to the root location on the default enabled site config, making sure to enable Websocket support. Pairing is done by &quot;openclaw devices list&quot; and &quot;openclaw devices approve &lt;request id&gt;&quot;. Make sure the dashboard shows that OpenClaw&#39;s health is OK. exe.dev handles forwarding from port 8000 to port 80/443 and HTTPS for us, so the final &quot;reachable&quot; should be &lt;vm-name&gt;.exe.xyz, without port specification.</span></span></code></pre></div><h2 id="수동-설치" tabindex="-1">수동 설치 <a class="header-anchor" href="#수동-설치" aria-label="Permalink to &quot;수동 설치&quot;">​</a></h2><h2 id="_1-vm-생성" tabindex="-1">1) VM 생성 <a class="header-anchor" href="#_1-vm-생성" aria-label="Permalink to &quot;1) VM 생성&quot;">​</a></h2><p>장치에서:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exe.dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span></span></code></pre></div><p>그런 다음 연결합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">vm-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.exe.xyz</span></span></code></pre></div><p>팁: 이 VM을 <strong>상태 유지</strong>로 유지합니다. OpenClaw는 <code>openclaw.json</code>, 에이전트별 <code>auth-profiles.json</code>, 세션 및 채널/제공자 상태를 <code>~/.openclaw/</code> 아래에, 작업 공간을 <code>~/.openclaw/workspace/</code> 아래에 저장합니다.</p><h2 id="_2-사전-요구-사항-설치-vm에서" tabindex="-1">2) 사전 요구 사항 설치 (VM에서) <a class="header-anchor" href="#_2-사전-요구-사항-설치-vm에서" aria-label="Permalink to &quot;2) 사전 요구 사항 설치 (VM에서)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ca-certificates</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openssl</span></span></code></pre></div><h2 id="_3-openclaw-설치" tabindex="-1">3) OpenClaw 설치 <a class="header-anchor" href="#_3-openclaw-설치" aria-label="Permalink to &quot;3) OpenClaw 설치&quot;">​</a></h2><p>OpenClaw 설치 스크립트를 실행합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://openclaw.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><h2 id="_4-openclaw를-포트-8000으로-프록시하도록-nginx-설정" tabindex="-1">4) OpenClaw를 포트 8000으로 프록시하도록 nginx 설정 <a class="header-anchor" href="#_4-openclaw를-포트-8000으로-프록시하도록-nginx-설정" aria-label="Permalink to &quot;4) OpenClaw를 포트 8000으로 프록시하도록 nginx 설정&quot;">​</a></h2><p><code>/etc/nginx/sites-enabled/default</code>를 다음으로 편집합니다</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>server {</span></span>
<span class="line"><span>    listen 80 default_server;</span></span>
<span class="line"><span>    listen [::]:80 default_server;</span></span>
<span class="line"><span>    listen 8000;</span></span>
<span class="line"><span>    listen [::]:8000;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    server_name _;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    location / {</span></span>
<span class="line"><span>        proxy_pass http://127.0.0.1:18789;</span></span>
<span class="line"><span>        proxy_http_version 1.1;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # WebSocket 지원</span></span>
<span class="line"><span>        proxy_set_header Upgrade $http_upgrade;</span></span>
<span class="line"><span>        proxy_set_header Connection &quot;upgrade&quot;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # 표준 프록시 헤더</span></span>
<span class="line"><span>        proxy_set_header Host $host;</span></span>
<span class="line"><span>        proxy_set_header X-Real-IP $remote_addr;</span></span>
<span class="line"><span>        proxy_set_header X-Forwarded-For $remote_addr;</span></span>
<span class="line"><span>        proxy_set_header X-Forwarded-Proto $scheme;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        # 장기 실행 연결을 위한 타임아웃 설정</span></span>
<span class="line"><span>        proxy_read_timeout 86400s;</span></span>
<span class="line"><span>        proxy_send_timeout 86400s;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>클라이언트 제공 체인을 보존하는 대신 전달 헤더를 덮어씁니다. OpenClaw는 명시적으로 구성된 프록시에서만 전달된 IP 메타데이터를 신뢰하며, 추가 방식 <code>X-Forwarded-For</code> 체인은 강화 위험으로 처리됩니다.</p><h2 id="_5-openclaw-액세스-및-권한-부여" tabindex="-1">5) OpenClaw 액세스 및 권한 부여 <a class="header-anchor" href="#_5-openclaw-액세스-및-권한-부여" aria-label="Permalink to &quot;5) OpenClaw 액세스 및 권한 부여&quot;">​</a></h2><p><code>https://&lt;vm-name&gt;.exe.xyz/</code>에 액세스합니다(온보딩의 Control UI 출력 참조). 인증을 요청하면 VM에서 구성된 공유 시크릿을 붙여넣습니다. 이 가이드는 토큰 인증을 사용하므로 <code>openclaw config get gateway.auth.token</code>으로 <code>gateway.auth.token</code>을 검색합니다(또는 <code>openclaw doctor --generate-gateway-token</code>으로 생성합니다). 게이트웨이를 비밀번호 인증으로 변경한 경우 <code>gateway.auth.password</code> / <code>OPENCLAW_GATEWAY_PASSWORD</code>를 사용합니다. <code>openclaw devices list</code> 및 <code>openclaw devices approve &lt;requestId&gt;</code>로 장치를 승인합니다. 확실하지 않은 경우 브라우저에서 Shelley를 사용하십시오!</p><h2 id="원격-액세스" tabindex="-1">원격 액세스 <a class="header-anchor" href="#원격-액세스" aria-label="Permalink to &quot;원격 액세스&quot;">​</a></h2><p>원격 액세스는 <a href="https://exe.dev" target="_blank" rel="noreferrer">exe.dev</a>의 인증으로 처리됩니다. 기본적으로 포트 8000의 HTTP 트래픽은 이메일 인증과 함께 <code>https://&lt;vm-name&gt;.exe.xyz</code>로 전달됩니다.</p><h2 id="업데이트" tabindex="-1">업데이트 <a class="header-anchor" href="#업데이트" aria-label="Permalink to &quot;업데이트&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw@latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span></span></code></pre></div><p>가이드: <a href="/openclaw-docs-ko/install/updating">업데이트</a></p>`,33)])])}const g=s(t,[["render",l]]);export{k as __pageData,g as default};
